--liquibase formatted sql

--changeset hospital-service:096-doctor-appointment-slots-fix
--comment: Re-seed appointment_slots with lowercase day keys (UI day keys are lowercase) and maxPatients=10 from DrChamberTime.xlsx. Replaces 095 data which used capitalised day names incompatible with the React day-toggle component. Also initialises off_days to an empty JSON array for all seeded doctors (DrChamberTime.xlsx contains only recurring weekly close/open patterns, not calendar holiday dates).

-- Reset all system-seeded doctors: clear stale slots and set off_days to empty array
UPDATE hospital.doctors
SET appointment_slots = NULL,
    off_days          = '[]',
    updated_at        = CURRENT_TIMESTAMP,
    updated_by        = 'system-import'
WHERE created_by = 'system-import'
   OR doctor_code LIKE 'TEST-DOC-%';

-- Seed corrected appointment_slots (lowercase day keys, maxPatients=10) from DrChamberTime.xlsx
